package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonObject_whenIsJsonObjectTrue_returnsThisAsJsonObject() {
    // Create an anonymous subclass of JsonElement that returns true for isJsonObject()
    // and implements deepCopy()
    JsonElement element = new JsonElement() {
      @Override
      public boolean isJsonObject() {
        return true;
      }

      @Override
      public JsonElement deepCopy() {
        return this;
      }

      @Override
      public String toString() {
        return "mockedJsonObjectElement";
      }
    };

    // Because getAsJsonObject casts 'this' to JsonObject, we cannot just return true for isJsonObject()
    // without actually being a JsonObject instance.
    // So we create a proxy that is both a JsonElement and a JsonObject.
    JsonObject proxy = new JsonObject() {
      @Override
      public boolean isJsonObject() {
        return true;
      }

      @Override
      public JsonElement deepCopy() {
        return this;
      }

      @Override
      public String toString() {
        return "mockedJsonObjectProxy";
      }
    };

    // The test is about getAsJsonObject returning 'this' when isJsonObject() is true.
    // So we test on the proxy object directly.
    JsonObject result = proxy.getAsJsonObject();
    assertSame(proxy, result);
  }

  @Test
  void getAsJsonObject_whenIsJsonObjectFalse_throwsIllegalStateException() {
    JsonElement element = new JsonElement() {
      @Override
      public boolean isJsonObject() {
        return false;
      }

      @Override
      public JsonElement deepCopy() {
        return this;
      }

      @Override
      public String toString() {
        return "mockedElement";
      }
    };

    IllegalStateException exception = assertThrows(IllegalStateException.class, element::getAsJsonObject);
    assertEquals("Not a JSON Object: mockedElement", exception.getMessage());
  }
}
